def execute_step(step: Step, previous_results: dict[int, str], tools: dict) -> str:
    """Execute one plan step using a ReAct sub-loop."""
    # Build context from relevant previous outputs
    context = "\n".join(
        f"Step {n} result: {r[:400]}"
        for n, r in sorted(previous_results.items())
    )
    prompt = f"""Complete this specific step using the tools available.

Previous step results:
{context}

Your step: {step.description}
Suggested tool: {step.tool}
Suggested input: {step.input_hint}

Use the ReAct format (Thought/Action/Observation) and end with:
Final Answer: <result of this step>
"""
    # Use a cheaper executor model
    llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
    # (abbreviated — uses react() from scratch or AgentExecutor)
    result = react(prompt, tools, max_steps=5)
    return result

def plan_and_execute(task: str, tools_dict: dict) -> str:
    """Full Plan-and-Execute loop."""
    tool_names = list(tools_dict.keys())
    plan = create_plan(task, tool_names)
    print(f"Plan: {len(plan.steps)} steps")

    step_results: dict[int, str] = {}
    for step in plan.steps:
        print(f"Executing step {step.step_number}: {step.description}")
        result = execute_step(step, step_results, tools_dict)
        step_results[step.step_number] = result
        print(f"  → {result[:120]}")

    # Final synthesis: combine all step results into the answer
    synthesis_prompt = f"""Task: {task}

Step results:
{"\n".join(f"Step {n}: {r}" for n, r in step_results.items())}

Write a final comprehensive answer that addresses the original task."""
    llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
    return llm.invoke(synthesis_prompt).content

def validate_plan(plan: Plan, available_tools: set[str]) -> list[str]:
    """Return a list of validation errors. Empty list = valid plan."""
    errors = []
    seen_steps = set()

    for step in plan.steps:
        # Check for duplicate step numbers
        if step.step_number in seen_steps:
            errors.append(f"Duplicate step number: {step.step_number}")
        seen_steps.add(step.step_number)

        # Check tool exists (None = synthesis step, always valid)
        if step.tool and step.tool not in available_tools:
            errors.append(
                f"Step {step.step_number} references unknown tool '{step.tool}'. "
                f"Available: {available_tools}"
            )

        # Check description is non-empty
        if not step.description.strip():
            errors.append(f"Step {step.step_number} has an empty description")

    # Check steps are numbered sequentially from 1
    expected = list(range(1, len(plan.steps) + 1))
    actual = sorted(seen_steps)
    if actual != expected:
        errors.append(f"Steps must be numbered 1..N sequentially. Got: {actual}")

    return errors

def create_validated_plan(task: str, tools: list[str], max_retries: int = 2) -> Plan:
    """Create a plan, validate it, and retry with error feedback if invalid."""
    for attempt in range(max_retries + 1):
        plan = create_plan(task, tools)
        errors = validate_plan(plan, set(tools))
        if not errors:
            return plan
        if attempt < max_retries:
            # Feed errors back to the planner
            task = task + f"\n\nPrevious plan had errors: {errors}. Fix these issues."
    raise ValueError(f"Could not produce valid plan after {max_retries + 1} attempts")

from pydantic import BaseModel

class ReplanDecision(BaseModel):
    action: str  # "continue" | "replan" | "finish"
    revised_steps: list[str] | None = None
    final_answer: str | None = None
    reason: str

def replanner_node_dynamic(state: PlanExecuteState) -> PlanExecuteState:
    """Decide whether to continue, replan, or finish based on step results."""
    if not state["plan"]:
        # All steps done — synthesize final answer
        return synthesize_answer(state)

    llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
    structured_llm = llm.with_structured_output(ReplanDecision)

    past_summary = "\n".join(f"Step: {s}\nResult: {r[:300]}" for s, r in state["past_steps"])
    prompt = f"""Original task: {state["input"]}

Completed steps:
{past_summary}

Remaining planned steps: {state["plan"]}

Decide whether to:
1. "continue" with the next planned step
2. "replan" the remaining steps (provide revised_steps list)
3. "finish" if the task is already answerable (provide final_answer)
"""
    decision = structured_llm.invoke(prompt)

    if decision.action == "finish":
        return {"response": decision.final_answer, "plan": []}
    elif decision.action == "replan" and decision.revised_steps:
        return {"plan": decision.revised_steps}
    else:
        return {"plan": state["plan"][1:]}  # advance to next step
